docker exec -i novelbridge-mysql mysql -u"${MYSQL_USER:-novel_bridge}" -p"${MYSQL_PASSWORD}" novel_bridge --default-character-set=utf8mb4 -e "SELECT c.id, c.book_id, LEFT(c.question,40) as q, r.error_type, LEFT(r.actual_answer,120) as answer FROM novel_eval_result r JOIN novel_eval_case c ON r.case_id = c.id WHERE r.run_id = 5 AND r.error_type != '' LIMIT 15;"